//! TIP Fee Manager dispatch tests.
//!
//! The dispatch implementation is auto-generated by the `#[contract(abi, dispatch)]` macro.

#[cfg(test)]
mod tests {
    use crate::{
        storage::{StorageCtx, hashmap::HashMapStorageProvider},
        test_util::{assert_full_coverage, check_selector_coverage},
        tip_fee_manager::{
            TipFeeManager,
            abi::IFeeManager::{ConstantsCalls, IFeeAMMCalls, InterfaceCalls},
        },
    };

    #[test]
    fn test_tip_fee_manager_selector_coverage() {
        let mut storage = HashMapStorageProvider::new(1);

        StorageCtx::enter(&mut storage, || {
            let mut fee_manager = TipFeeManager::new();

            let fee_manager_unsupported = check_selector_coverage(
                &mut fee_manager,
                InterfaceCalls::SELECTORS,
                "Interface",
                InterfaceCalls::name_by_selector,
            );

            let amm_unsupported = check_selector_coverage(
                &mut fee_manager,
                IFeeAMMCalls::SELECTORS,
                "IFeeAMM",
                IFeeAMMCalls::name_by_selector,
            );

            let constants_unsupported = check_selector_coverage(
                &mut fee_manager,
                ConstantsCalls::SELECTORS,
                "Constants",
                ConstantsCalls::name_by_selector,
            );

            assert_full_coverage([
                fee_manager_unsupported,
                amm_unsupported,
                constants_unsupported,
            ]);
        })
    }
}
